SELECT event_name, prize_money 
FROM events 
ORDER BY event_name;

SELECT event_name, number_of_participants
FROM events
ORDER BY number_of_participants DESC;

SELECT MAX(number_of_participants) AS max_participants
FROM events
WHERE prize_money = (SELECT MAX(prize_money) FROM events);

SELECT event_name
FROM events
ORDER BY event_date, event_type;
